import styled from 'styled-components';
import { motion } from "framer-motion/dist/framer-motion"; 

export const MintContainer = styled.div`
height: 100vh;
z-index: 1;
background-color: #F0FFE6;
`;

export const MintWrapper = styled.div`
display: flex;
flex-direction: column;
width: 100%;
height: 100%;
max-width: 1100px;
margin-left: auto;
margin-right: auto;
justify-content: center;
align-items: center;
padding: 0 25px 0 25px;
`;

export const MintContent = styled.div`
display: flex;
flex-direction: column;
background: #33682C;
border: 4px solid #fff;
box-shadow: 10px 15px rgba(0, 0, 0, 0.05);
width: 100%;
max-width: 600px;
height: auto;
border-radius: 10px;
padding: 25px 25px 25px 25px;
z-index: 2;
`;

export const MintHeader = styled.h1`
font-size: 36px;
font-weight: bold;
color: #fff;
text-align: center;

@media screen and (max-width: 768px) {
    font-size: 32px;
}

@media screen and (max-width: 480px) {
    font-size: 28px;
}
`;

export const MintDesc = styled.p`
font-size: 24px;
color: #fff;
text-align: center;
margin-top: 25px;
width: 100%;

@media screen and (max-width: 768px) {
    font-size: 18px;
}

@media screen and (max-width: 480px) {
    font-size: 14px;
}
`;

export const MintDesc2 = styled.p`
font-size: 18px;
color: #fff;
text-align: center;
margin-top: 25px;
width: 100%;

@media screen and (max-width: 768px) {
    font-size: 16px;
}

@media screen and (max-width: 480px) {
    font-size: 14px;
}
`;

export const MintWalletText = styled.span`
color: #E7EB76;
font-size: 18px;
margin-top: 5px;
font-weight: bold;
text-align: center;

@media screen and (max-width: 768px) {
    font-size: 16px;
}

@media screen and (max-width: 480px) {
    font-size: 12px;
}
`;

export const MintLink = styled.a`
font-size: 18px;
color: #fff;
text-align: center;
margin-top: 25px;

&:hover {
    transition: all 0.2s ease-in-out;
    cursor: pointer;
    transform: scale(1.02);
    letter-spacing: 1px;
    color: #7d0e00;
}

@media screen and (max-width: 768px) {
    font-size: 16px;
}

@media screen and (max-width: 480px) {
    font-size: 14px;
}
`;

export const MintImage = styled(motion.img)`
width: 100%;
max-width: 300px;
height: auto;
margin-left: auto;
margin-right: auto;
margin-bottom: 50px;
z-index: 1;
`;

export const ConnectButton = styled.button`
font-size: 24px;
font-weight: bold;
color: #33682C;
background-color: #E7EB76;
border: 4px solid #fff;
border-radius: 5px;
margin-left: auto;
margin-right: auto;
margin-top: 25px;
box-shadow: 10px 10px rgba(0, 0, 0, 0.1);
padding: 10px 25px;

@media screen and (max-width: 768px) {
    font-size: 22px;
}

@media screen and (max-width: 480px) {
    font-size: 18px;
}

&:hover {
    cursor: pointer;
    transform: scale(1.1) rotate(2.5deg);
    transition: all 0.2s ease-in-out;
    border: 4px solid #b3b946;
    box-shadow: 12px 14px rgba(0, 0, 0, 0.2);
    letter-spacing: 2px;
}
`;

export const AmountWrapper = styled.div`
display: flex;
flex-direction: row;
margin-left: auto;
margin-right: auto;
margin-top: 50px;
margin-bottom: 25px;
`;

export const AmountButton = styled.button`
width: 40px;
height: 40px;
font-size: 15px;
color: #fff;
border: 2px solid #fff;
background-color: #8DBC46;
border-radius: 10px;
box-shadow: 5px 5px rgba(0, 0, 0, 0.1);
margin-top: auto;
margin-bottom: auto;

&:hover {
    transition: all 0.2s ease-in-out;
    transform: scale(1.1);
    cursor: pointer;
}
`;

export const AmountText = styled.h1`
font-size: 36px;
color: #fff;
margin-left: 25px;
margin-right: 25px;
margin-top: auto;
margin-bottom: auto;
`;

export const WrongChainText = styled.p`
font-size: 18px;
color: #E7EB76;
text-align: center;
margin-top: 25px;

@media screen and (max-width: 768px) {
    font-size: 16px;
}

@media screen and (max-width: 480px) {
    font-size: 14px;
}
`;

export const ContractText = styled.a`
font-size: 18px;
font-weight: bold;
color: #33682C;
margin-top: 40px;

@media screen and (max-width: 768px) {
    font-size: 16px;
}

@media screen and (max-width: 480px) {
    font-size: 14px;
}
`;
