/* eslint-disable no-unused-vars */
/* eslint-disable react-hooks/exhaustive-deps */
import React, { useState, useEffect } from 'react';
import { useMetaMask } from 'metamask-react';
import {
  MintContainer,
  MintContent,
  MintHeader,
  MintImage,
  MintWrapper,
  ConnectButton,
  MintDesc,
  MintLink,
  MintWalletText,
  MintDesc2,
  AmountWrapper,
  AmountButton,
  AmountText,
  WrongChainText,
  ContractText
} from './mintElements';
import { CheckNetwork } from '../../utils/changeNetwork';
import { CarbonCollectible } from '../../constants/collections.json'
import { FaChevronRight, FaChevronLeft } from 'react-icons/fa'
import Web3 from 'web3-eth-contract';
import web3 from 'web3';
import Abis from '../../constants/abis.json'
import img1 from '../../images/logo2.png';

const MintSection = () => {
  const { connect, account, ethereum, chainId } = useMetaMask();
  Web3.setProvider(ethereum);

  const [loading, setLoading] = useState(false);
  const {
    main: to, methods: {
      mint, totalSupply, getPrice, getMaxMintAmount,
    },
  } = new Web3(Abis.main, CarbonCollectible.contract);

  const [currentSupply, setCurrentSupply] = useState(0);
  const [price, setPrice] = useState(0);
  const [maxMintAmount, setMaxMintAmount] = useState(0);

  const CallCurrentSupply = () => totalSupply().call().then((current) => setCurrentSupply(current));
  const CallPrice = () => getPrice().call().then((current) => setPrice(web3.utils.fromWei(current.toString(), 'ether')));
  const CallMaxMintAmount = () => getMaxMintAmount().call().then((current) => setMaxMintAmount(current));

  const [feedback, setFeedback] = useState("");
  const [amount, setAmount] = useState(1);

  const handleConnect = async () => {
    if (window.ethereum.networkVersion === CarbonCollectible.chainId)
      await connect();
  };

  const decrementMintAmount = () => {
    let newMintAmount = amount - 1;
    if (newMintAmount < 1) {
      newMintAmount = 1;
    }
    setAmount(newMintAmount);
  };

  const incrementMintAmount = () => {
    let newMintAmount = amount + 1;
    if (newMintAmount > maxMintAmount) {
      newMintAmount = maxMintAmount;
    }
    setAmount(newMintAmount);
  };

  useEffect(() => { if (account) { CallCurrentSupply(); CallPrice(); CallMaxMintAmount(); }}, [account, chainId]);
  useEffect(() => setFeedback(`Maximum ${maxMintAmount} NFTs per transaction`), [maxMintAmount]);

  const mintNft = async () => {
    await CheckNetwork(CarbonCollectible.chainId);

    setLoading(true);
    mint(amount).estimateGas({from: account, to, value: web3.utils.toWei((price * amount).toString(), "ether")})
      .then((gasEstimate) => mint(amount).send({from: account, to, gas: gasEstimate + 100000, value: web3.utils.toWei((price * amount).toString(), "ether")}))
      .then(() => setFeedback(`Successfully minted ${amount} ${CarbonCollectible.nftName}`))
      .catch(() => setFeedback("Insufficient funds or you are not in pre-sale list"))
    .catch(() => setFeedback("Can't connect to contract... Please try again later."))
    .finally(() => { setLoading(false); CallCurrentSupply(); });
  };

  return (
    <MintContainer>
      <MintWrapper>
        <MintImage
        initial={{ y: '100%', opacity: 0, scale: 0.5 }}
        animate={{ y: 0, opacity: 1, scale: 1 }}
        transition={{ duration: 0.5 }}
        src={img1} alt="bear" />
        {!window.ethereum ? (
          <MintContent>
            <MintHeader>Metamask extension not detected!</MintHeader>
            <MintLink href='https://metamask.io/' target="_blank">Please download Metamask</MintLink>
          </MintContent>
        ) : (
          <>
            {account ? (
            <>
              {window.ethereum.networkVersion !== CarbonCollectible.chainId ? (
              <MintContent>
                <MintHeader>Please change your network</MintHeader>
                <MintDesc2>{`${CarbonCollectible.nftName} are on ${CarbonCollectible.blockchain} Blockchain`}</MintDesc2>
                <WrongChainText>{`Please switch to ${CarbonCollectible.blockchain} mainnet.`}</WrongChainText>
                <ConnectButton onClick={() => CheckNetwork(CarbonCollectible.chainId)}>Switch</ConnectButton>
              </MintContent>
              ) : (
              <MintContent>
                <MintHeader>Minting is live!</MintHeader>
                <MintDesc>Connected wallet:</MintDesc> 
                <MintWalletText>{account}</MintWalletText>         
                <AmountWrapper>
                  <AmountButton disabled={loading} onClick={() => decrementMintAmount()}><FaChevronLeft/></AmountButton>
                  <AmountText>{amount}</AmountText>
                  <AmountButton disabled={loading} onClick={() => incrementMintAmount()}><FaChevronRight/></AmountButton>
                </AmountWrapper>
                <MintDesc2>{loading ? 'Please wait' : `${feedback}`}</MintDesc2>
                <ConnectButton disabled={loading} onClick={() => mintNft()}>{loading ? 'Minting...' : `Mint for ${price * amount} ${CarbonCollectible.currency}`}</ConnectButton>
              </MintContent>
              )}
            </>
            ) : (
            <MintContent>
              <MintHeader>Please connect your wallet</MintHeader>
              <MintDesc2>{`${CarbonCollectible.nftName} are on ${CarbonCollectible.blockchain} Blockchain`}</MintDesc2>
              {window.ethereum.networkVersion !== CarbonCollectible.chainId && 
              <WrongChainText>{`Please switch to ${CarbonCollectible.blockchain} mainnet.`}</WrongChainText>
              }
              <ConnectButton onClick={() => {window.ethereum.networkVersion !== CarbonCollectible.chainId ? CheckNetwork(CarbonCollectible.chainId) : handleConnect()}}>{window.ethereum.networkVersion !== CarbonCollectible.chainId ? `Switch` : 'Connect'}</ConnectButton>
            </MintContent>
            )}
          </>
        )}
        <ContractText href={CarbonCollectible.contract_link} target="_blank">{`Contract: ${CarbonCollectible.contract}`}</ContractText>
      </MintWrapper>
    </MintContainer>
  );
};

export default MintSection;
